// LESSON: Reference Page 1 - I/O, Path, Files.
// You will learn: Read, write, and close files with Path, Files, and resources.
class Prog2Reference436 {
  // EXEMPEL 1: Path beskriver var en fil finns och Files laser innehall.
  static java.util.List<String> readLines(String fileName) throws java.io.IOException {
    java.nio.file.Path path = java.nio.file.Paths.get(fileName);
    return java.nio.file.Files.readAllLines(path, java.nio.charset.StandardCharsets.UTF_8);
  }
  // EXEMPEL 2: Files kan skriva en hel lista rader till en fil.
  static void writeLines(String fileName, java.util.List<String> lines) throws java.io.IOException {
    java.nio.file.Path path = java.nio.file.Paths.get(fileName);
    java.nio.file.Files.write(path, lines, java.nio.charset.StandardCharsets.UTF_8);
  }
  // EXEMPEL 3: BufferedWriter och PrintWriter ger radvis skrivning.
  static void printOneLine(String fileName, String line) throws java.io.IOException {
    java.nio.file.Path path = java.nio.file.Paths.get(fileName);
    try (java.io.PrintWriter out = new java.io.PrintWriter(java.nio.file.Files.newBufferedWriter(path))) {
      out.println(line);
    }
  }
}
